#!/bin/bash
# Run BoltzGen for all 22 DesignBench targets: 100 designs per target.
# Task: antibody or nanobody.
# Requires: BoltzGen env, configs generated by generate_designbench_specs.py.
#
# Usage:
#   ./run_boltzgen_designbench.sh antibody  /path/to/boltzgen_output
#   ./run_boltzgen_designbench.sh nanobody  /path/to/boltzgen_output
#
# Each target runs: boltzgen run configs/{task}/{target_id}.yaml --output {out_root}/{task}/{target_id} --num_designs 100

set -e
TASK="${1:-nanobody}"
OUT_ROOT="${2:-./boltzgen_designbench_out}"
CONFIGS_DIR="$(cd "$(dirname "$0")" && pwd)/configs"
SPEC_DIR="${CONFIGS_DIR}/${TASK}"

if [[ "$TASK" != "antibody" && "$TASK" != "nanobody" ]]; then
  echo "Usage: $0 antibody|nanobody [output_root]"
  exit 1
fi

if [[ ! -d "$SPEC_DIR" ]]; then
  echo "Run generate_designbench_specs.py first to create configs under $CONFIGS_DIR"
  exit 1
fi

mkdir -p "$OUT_ROOT"
echo "Task: $TASK  Output root: $OUT_ROOT"

for yaml in "$SPEC_DIR"/*.yaml; do
  [[ -f "$yaml" ]] || continue
  target_id=$(basename "$yaml" .yaml)
  out_dir="${OUT_ROOT}/${TASK}/${target_id}"
  echo "Running $target_id -> $out_dir"
  boltzgen run "$yaml" \
    --output "$out_dir" \
    --num_designs 100 \
    --protocol protein-anything \
    --steps design
done

echo "Done. Next: run convert_boltzgen_to_designbench.py to produce design_dir + cdr_info.csv"
